sys_ws_operation.operation_script:
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    const api = new x_neyu_jr_api.JobRelatednessAPI();

	// Check required parameters
    var paramCheck = api.checkForParams(request);
    if (paramCheck.error == false) {

		// Check optional course parameters
        var courseCheck = api.checkOptCourses(request);
        if (courseCheck.error == false) {

			// Create record
            var createCheck = api.createRequest(request);
            gs.info("createRequest response:" + JSON.stringify(createCheck));

        } else {
			// Log optional course error
            gs.info("checkOptCourses response:" + JSON.stringify(courseCheck));
        }
    } else {
		// Log required parameters error
        gs.info("checkForParams response:" + JSON.stringify(paramCheck));
    }


})(request, response);
